import sqlite3InitModule from '@sqlite.org/sqlite-wasm';
import { applyLocalDbArtifacts, applyLocalDbTriggers } from './local-db-artifacts.js';

type WorkerRequest = {
    type: 'db-request';
    requestId: string;
    command: string;
    payload?: unknown;
};

type WorkerResponse = {
    requestId: string;
    ok: boolean;
    result?: unknown;
    error?: string;
};

type SQLite3Module = Awaited<ReturnType<typeof sqlite3InitModule>>;

type SqlExecOptions = {
    sql: string;
    bind?: unknown[];
    rowMode?: 'array' | 'object' | 'stmt' | number | string;
    resultRows?: unknown[];
    returnValue?: 'this' | 'resultRows' | 'saveSql';
};

type SqliteDb = {
    exec(sqlOrOptions: string | SqlExecOptions): unknown;
    changes(total?: boolean, sixtyFour?: boolean): number | bigint;
    selectValue(sql: string, bind?: unknown, asType?: number): unknown;
    close(): void;
};

type SqliteDbCtor = new (filename: string, mode?: string) => SqliteDb;

type SqliteModuleWithOo1 = SQLite3Module & {
    oo1: {
        DB: SqliteDbCtor;
        OpfsDb?: SqliteDbCtor & {
            importDb(filename: string, data: Uint8Array | ArrayBuffer): Promise<number>;
        };
    };
};

const DB_FILENAME = '/motivation.db';

let sqliteModulePromise: Promise<SqliteModuleWithOo1> | null = null;
let dbPromise: Promise<SqliteDb> | null = null;
let hasInitializedSchema = false;
let hasLoadedSnapshot = false;
let operationQueue: Promise<void> = Promise.resolve();

const isObject = (value: unknown): value is Record<string, unknown> => typeof value === 'object' && value !== null;

const SQLITE_MAGIC_HEADER = new TextEncoder().encode('SQLite format 3\0');

const hasValidSqliteHeader = (buffer: ArrayBuffer): boolean => {
    if (buffer.byteLength < SQLITE_MAGIC_HEADER.length) {
        return false;
    }

    const bytes = new Uint8Array(buffer, 0, SQLITE_MAGIC_HEADER.length);
    for (let i = 0; i < SQLITE_MAGIC_HEADER.length; i += 1) {
        if (bytes[i] !== SQLITE_MAGIC_HEADER[i]) {
            return false;
        }
    }
    return true;
};

const runSerialized = async <T>(operation: () => Promise<T>): Promise<T> => {
    const scheduled = operationQueue.then(operation, operation);
    operationQueue = scheduled.then(() => undefined, () => undefined);
    return scheduled;
};

const getSqliteModule = async (): Promise<SqliteModuleWithOo1> => {
    if (!sqliteModulePromise) {
        sqliteModulePromise = sqlite3InitModule().then((module) => module as SqliteModuleWithOo1);
    }
    return sqliteModulePromise;
};

const openDatabase = async (): Promise<SqliteDb> => {
    if (dbPromise) {
        try {
            return await dbPromise;
        } catch (err) {
            console.warn('[SYNC-DEBUG][worker] Previous dbPromise was rejected, clearing and retrying...', err);
            dbPromise = null;
        }
    }

    dbPromise = (async () => {
        const sqlite3 = await getSqliteModule();
        console.debug('[SYNC-DEBUG][worker] Opening database, OPFS available:', Boolean(sqlite3.oo1.OpfsDb));

        if (!sqlite3.oo1.OpfsDb) {
            console.warn('[SYNC-DEBUG][worker] OPFS not available');
            throw new Error('[SYNC-DEBUG][worker] OPFS not available');
        }

        try {
            const db = new sqlite3.oo1.OpfsDb(DB_FILENAME, 'c') as unknown as SqliteDb;
            console.debug('[SYNC-DEBUG][worker] OPFS database opened successfully');
            return db;
        } catch (err) {
            console.error('[SYNC-DEBUG][worker] OPFS database open FAILED:', err);
            throw err;
        }
    })();

    return dbPromise;
};

const closeDatabase = async (): Promise<void> => {
    if (!dbPromise) {
        return;
    }

    const db = await dbPromise;
    db.close();
    dbPromise = null;
};

const hasOpfsSnapshot = async (): Promise<boolean> => {
    const sqlite3 = await getSqliteModule();
    if (!sqlite3.oo1.OpfsDb) {
        const fallback = hasLoadedSnapshot || hasInitializedSchema;
        console.debug('[SYNC-DEBUG][worker] hasOpfsSnapshot (no OPFS):', fallback, { hasLoadedSnapshot, hasInitializedSchema });
        return fallback;
    }

    try {
        const readOnlyDb = new sqlite3.oo1.OpfsDb(DB_FILENAME, 'r');
        readOnlyDb.close();
        console.debug('[SYNC-DEBUG][worker] hasOpfsSnapshot: true (OPFS file exists)');
        return true;
    } catch (err) {
        console.debug('[SYNC-DEBUG][worker] hasOpfsSnapshot: false (OPFS file not found):', err);
        return false;
    }
};

const ensureSchema = async (): Promise<void> => {
    await runSerialized(async () => {
        console.debug('[SYNC-DEBUG][worker] ensureSchema — applying local DB artifacts...');
        const db = await openDatabase();
        applyLocalDbArtifacts(db);
        hasInitializedSchema = true;
        console.debug('[SYNC-DEBUG][worker] ensureSchema — DONE');
    });
};

const executeQuery = async (payload: unknown): Promise<unknown[]> => {
    if (!isObject(payload) || typeof payload.sql !== 'string') {
        throw new Error('query payload must include sql string');
    }
    const requestPayload = payload as { sql: string; params?: unknown[] };

    return runSerialized(async () => {
        const db = await openDatabase();
        const resultRows: unknown[] = [];

        const options: SqlExecOptions = {
            sql: requestPayload.sql,
            rowMode: 'object',
            resultRows,
            returnValue: 'resultRows',
        };

        if (Array.isArray(requestPayload.params) && requestPayload.params.length > 0) {
            options.bind = requestPayload.params;
        }

        db.exec(options);
        return resultRows;
    });
};

const executeStatement = async (payload: unknown): Promise<{ changes: number; lastInsertRowid: number }> => {
    if (!isObject(payload) || typeof payload.sql !== 'string') {
        throw new Error('execute payload must include sql string');
    }
    const requestPayload = payload as { sql: string; params?: unknown[] };

    return runSerialized(async () => {
        const db = await openDatabase();

        const options: SqlExecOptions = {
            sql: requestPayload.sql,
            returnValue: 'this',
        };

        if (Array.isArray(requestPayload.params) && requestPayload.params.length > 0) {
            options.bind = requestPayload.params;
        }

        db.exec(options);

        const changesValue = db.changes();
        const lastInsertRowidValue = db.selectValue('SELECT last_insert_rowid()');

        return {
            changes: Number(changesValue ?? 0),
            lastInsertRowid: Number(lastInsertRowidValue ?? 0),
        };
    });
};

const loadSnapshot = async (payload: unknown): Promise<void> => {
    if (!isObject(payload) || !(payload.buffer instanceof ArrayBuffer)) {
        throw new Error('load-snapshot payload must include buffer ArrayBuffer');
    }
    const snapshotBuffer = payload.buffer;
    console.debug('[SYNC-DEBUG][worker] loadSnapshot — buffer size:', snapshotBuffer.byteLength);

    const sqlite3 = await getSqliteModule();
    if (!sqlite3.oo1.OpfsDb) {
        throw new Error('OPFS is unavailable in this environment; cannot import SQLite snapshot');
    }

    if (!hasValidSqliteHeader(snapshotBuffer)) {
        console.error('[SYNC-DEBUG][worker] loadSnapshot — INVALID SQLite header!');
        throw new Error('Invalid SQLite snapshot header');
    }
    console.debug('[SYNC-DEBUG][worker] loadSnapshot — valid SQLite header confirmed');

    await runSerialized(async () => {
        const previousDbPromise = dbPromise ?? openDatabase();
        dbPromise = (async () => {
            try {
                const oldDb = await previousDbPromise;
                oldDb.close();
                console.debug('[SYNC-DEBUG][worker] loadSnapshot — old DB closed, importing...');

                await sqlite3.oo1.OpfsDb!.importDb(DB_FILENAME, snapshotBuffer);
                console.debug('[SYNC-DEBUG][worker] loadSnapshot — importDb done, re-opening...');
                const importedDb = new sqlite3.oo1.OpfsDb!(DB_FILENAME, 'c') as unknown as SqliteDb;
                applyLocalDbTriggers(importedDb);
                hasLoadedSnapshot = true;
                hasInitializedSchema = true;
                console.debug('[SYNC-DEBUG][worker] loadSnapshot — snapshot loaded and triggers applied');

                return importedDb;
            } catch (err) {
                console.error('[SYNC-DEBUG][worker] loadSnapshot — FAILED:', err);
                // Clear dbPromise so next openDatabase call can try again
                dbPromise = null;
                throw err;
            }
        })();

        await dbPromise;
    });
};

const postResponse = (port: MessagePort, response: WorkerResponse): void => {
    port.postMessage(response);
};

const wipeOpfs = async (): Promise<void> => {
    console.debug('[SYNC-DEBUG][worker] wipeOpfs — closing DB...');
    await closeDatabase();
    try {
        const root = await navigator.storage.getDirectory();
        await root.removeEntry('motivation.db');
        console.debug('[SYNC-DEBUG][worker] wipeOpfs — OPFS file removed');
    } catch (e) {
        console.warn('[SYNC-DEBUG][worker] wipeOpfs — failed to remove OPFS file:', e);
        console.warn('Failed to wipe OPFS database', e);
    }
};

const handleRequest = async (request: WorkerRequest): Promise<unknown> => {
    console.debug('[SYNC-DEBUG][worker] handleRequest:', request.command);
    const start = performance.now();
    try {
        let result: unknown;
        switch (request.command) {
            case 'db-exists':
                result = await hasOpfsSnapshot();
                break;
            case 'load-snapshot':
                await loadSnapshot(request.payload);
                result = undefined;
                break;
            case 'schema-init':
                await ensureSchema();
                result = undefined;
                break;
            case 'query':
                result = await executeQuery(request.payload);
                break;
            case 'execute':
                result = await executeStatement(request.payload);
                break;
            case 'wipe':
                await wipeOpfs();
                result = undefined;
                break;
            default:
                throw new Error(`Unknown DB worker command: ${request.command}`);
        }
        const elapsed = (performance.now() - start).toFixed(1);
        console.log(`[SYNC-DEBUG][worker] handleRequest ${request.command} — OK (${elapsed}ms)`);
        return result;
    } catch (err) {
        const elapsed = (performance.now() - start).toFixed(1);
        console.error(`[SYNC-DEBUG][worker] handleRequest ${request.command} — FAILED (${elapsed}ms):`, err);
        throw err;
    }
};

const workerScope = globalThis as unknown as {
    onmessage: ((event: MessageEvent<WorkerRequest>) => void) | null;
};

workerScope.onmessage = async (event: MessageEvent<WorkerRequest>) => {
    const request = event.data;
    const responsePort = event.ports?.[0];

    if (!request || request.type !== 'db-request' || !responsePort) {
        console.warn('Ignoring malformed DB worker message', {
            hasRequest: Boolean(request),
            requestType: request?.type,
            hasResponsePort: Boolean(responsePort),
        });
        return;
    }

    try {
        const result = await handleRequest(request);
        postResponse(responsePort, {
            requestId: request.requestId,
            ok: true,
            result,
        });
    } catch (error) {
        postResponse(responsePort, {
            requestId: request.requestId,
            ok: false,
            error: error instanceof Error ? error.message : 'Unknown worker error',
        });
    }
};
