import { PENDING_CHANGES_TABLE_SQL } from '@motivation/shared';
import { OFFLINE_FALLBACK_SCHEMA_SQL } from './fallback-schema.js';
import { PENDING_CHANGES_TRIGGERS_SQL } from './pending-changes.js';

type SqlExecTarget = {
    exec(sql: string): unknown;
};

// Full init — used when there is no snapshot (pure offline from scratch).
// Creates all user-data tables, the _pending_changes table, and triggers.
export function applyLocalDbArtifacts(db: SqlExecTarget): void {
    db.exec(OFFLINE_FALLBACK_SCHEMA_SQL);
    db.exec(PENDING_CHANGES_TABLE_SQL);
    db.exec(PENDING_CHANGES_TRIGGERS_SQL);
}

// Post-snapshot — the snapshot already contains all tables (including _pending_changes
// from server migration 011). Only triggers need to be (re-)created.
export function applyLocalDbTriggers(db: SqlExecTarget): void {
    db.exec(PENDING_CHANGES_TRIGGERS_SQL);
}