import { PENDING_CHANGES_TABLE_SQL, TRACKED_TABLES, type TrackedTable } from '@motivation/shared';

export { PENDING_CHANGES_TABLE_SQL } from '@motivation/shared';

function buildJsonObjectSql(alias: 'NEW' | 'OLD', columns: string[]): string {
    return `json_object(${columns.flatMap((column) => [`'${column}'`, `${alias}.${column}`]).join(', ')})`;
}

function buildInsertOrUpdateTriggerSql(table: TrackedTable, operation: 'INSERT' | 'UPDATE'): string {
    const triggerName = `_pending_changes_${table.tableName.toLowerCase()}_${operation.toLowerCase()}`;
    return [
        `DROP TRIGGER IF EXISTS ${triggerName};`,
        `CREATE TRIGGER ${triggerName}`,
        `AFTER ${operation} ON ${table.tableName}`,
        'BEGIN',
        `    INSERT INTO _pending_changes (table_name, row_id, operation, row_data) VALUES ('${table.tableName}', NEW.${table.rowIdColumn}, '${operation}', ${buildJsonObjectSql('NEW', table.columns)});`,
        'END;',
    ].join('\n');
}

function buildDeleteTriggerSql(table: TrackedTable): string {
    const triggerName = `_pending_changes_${table.tableName.toLowerCase()}_delete`;
    return [
        `DROP TRIGGER IF EXISTS ${triggerName};`,
        `CREATE TRIGGER ${triggerName}`,
        `AFTER DELETE ON ${table.tableName}`,
        'BEGIN',
        `    INSERT INTO _pending_changes (table_name, row_id, operation, row_data) VALUES ('${table.tableName}', OLD.${table.rowIdColumn}, 'DELETE', NULL);`,
        'END;',
    ].join('\n');
}

// Triggers only — re-applied after snapshot load (table already present in snapshot).
export const PENDING_CHANGES_TRIGGERS_SQL = TRACKED_TABLES.flatMap((table) => [
    buildInsertOrUpdateTriggerSql(table, 'INSERT'),
    buildInsertOrUpdateTriggerSql(table, 'UPDATE'),
    buildDeleteTriggerSql(table),
]).join('\n');

// Table + triggers — used for full offline init without a snapshot.
export const OFFLINE_PENDING_CHANGES_SQL = [
    PENDING_CHANGES_TABLE_SQL,
    PENDING_CHANGES_TRIGGERS_SQL,
].join('\n');
