// Single source of truth for every user-data table definition.
// Imported by:
//   - server migrations (CREATE TABLE statements)
//   - pwa/src/db/fallback-schema.ts (offline fallback schema)
//   - pwa/src/db/pending-changes.ts (trigger column lists)
//   - server sync endpoint (table/column allowlist — Step 4)

// ──────────────────────────────────────────────────────────
// Section schemas (CREATE TABLE + indexes, IF NOT EXISTS)
// ──────────────────────────────────────────────────────────

export const HEALTH_TABLES_SQL: string[] = [
    `CREATE TABLE IF NOT EXISTS activities (
        id TEXT PRIMARY KEY,
        type TEXT NOT NULL,
        source TEXT NOT NULL CHECK(source IN ('manual', 'strava', 'calendar')),
        title TEXT NOT NULL,
        description TEXT,
        date TEXT NOT NULL,
        duration_minutes INTEGER,
        calories_burned INTEGER,
        external_id TEXT,
        metadata TEXT,
        created_at TEXT DEFAULT (datetime('now')),
        updated_at TEXT DEFAULT (datetime('now'))
    );`,
    'CREATE INDEX IF NOT EXISTS idx_activities_date ON activities(date);',
    'CREATE INDEX IF NOT EXISTS idx_activities_source ON activities(source);',
    'CREATE UNIQUE INDEX IF NOT EXISTS idx_activities_external_id ON activities(external_id) WHERE external_id IS NOT NULL;',
    `CREATE TABLE IF NOT EXISTS food_items (
        id TEXT PRIMARY KEY,
        canonical_name TEXT NOT NULL,
        display_name TEXT NOT NULL,
        brand TEXT,
        barcode TEXT,
        source TEXT NOT NULL CHECK(source IN ('manual', 'openfoodfacts', 'ai_estimate', 'mfp_import')),
        source_ref TEXT,
        base_amount REAL NOT NULL,
        base_unit TEXT NOT NULL CHECK(base_unit IN ('g', 'ml', 'piece')),
        default_serving_amount REAL,
        serving_label TEXT,
        serving_quantity REAL,
        calories_per_base REAL,
        protein_g_per_base REAL,
        carbs_g_per_base REAL,
        fat_g_per_base REAL,
        fiber_g_per_base REAL,
        sugar_g_per_base REAL,
        sodium_mg_per_base REAL,
        use_count INTEGER NOT NULL DEFAULT 1,
        last_used_at TEXT NOT NULL DEFAULT (datetime('now')),
        raw_json TEXT,
        image_path TEXT,
        archived_at TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    ) STRICT;`,
    'CREATE INDEX IF NOT EXISTS idx_food_items_canonical_name ON food_items(canonical_name);',
    'CREATE INDEX IF NOT EXISTS idx_food_items_usage ON food_items(use_count DESC, last_used_at DESC);',
    'CREATE UNIQUE INDEX IF NOT EXISTS idx_food_items_barcode ON food_items(barcode) WHERE barcode IS NOT NULL;',
    'CREATE INDEX IF NOT EXISTS idx_food_items_source_ref ON food_items(source, source_ref);',
    `CREATE TABLE IF NOT EXISTS ai_estimations (
        food_item_id TEXT PRIMARY KEY,
        model_name TEXT NOT NULL,
        prompt_used TEXT NOT NULL,
        image_path TEXT,
        confidence_score REAL,
        raw_response TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        FOREIGN KEY (food_item_id) REFERENCES food_items(id) ON DELETE CASCADE
    ) STRICT;`,
    `CREATE TABLE IF NOT EXISTS meals (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        notes TEXT,
        default_scale REAL NOT NULL DEFAULT 1.0,
        use_count INTEGER NOT NULL DEFAULT 0,
        last_used_at TEXT,
        image_path TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    ) STRICT;`,
    `CREATE TABLE IF NOT EXISTS meal_ingredients (
        id TEXT PRIMARY KEY,
        meal_id TEXT NOT NULL,
        food_item_id TEXT NOT NULL,
        amount REAL NOT NULL,
        position INTEGER NOT NULL DEFAULT 0,
        FOREIGN KEY (meal_id) REFERENCES meals(id) ON DELETE CASCADE,
        FOREIGN KEY (food_item_id) REFERENCES food_items(id) ON DELETE RESTRICT
    ) STRICT;`,
    'CREATE INDEX IF NOT EXISTS idx_meal_ingredients_meal_id ON meal_ingredients(meal_id);',
    'CREATE INDEX IF NOT EXISTS idx_meal_ingredients_food_item_id ON meal_ingredients(food_item_id);',
    `CREATE TABLE IF NOT EXISTS consumption_entries (
        id TEXT PRIMARY KEY,
        date TEXT NOT NULL,
        meal_type TEXT NOT NULL CHECK(meal_type IN ('Breakfast', 'Lunch', 'Dinner', 'Snacks')),
        food_item_id TEXT NOT NULL,
        amount REAL NOT NULL,
        calories REAL,
        protein_g REAL,
        carbs_g REAL,
        fat_g REAL,
        fiber_g REAL,
        sugar_g REAL,
        sodium_mg REAL,
        source_meal_id TEXT,
        meal_occurrence_id TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now')),
        FOREIGN KEY (food_item_id) REFERENCES food_items(id) ON DELETE RESTRICT,
        FOREIGN KEY (source_meal_id) REFERENCES meals(id) ON DELETE SET NULL
    ) STRICT;`,
    'CREATE INDEX IF NOT EXISTS idx_consumption_entries_date ON consumption_entries(date);',
    'CREATE INDEX IF NOT EXISTS idx_consumption_entries_meal_type ON consumption_entries(meal_type);',
    'CREATE INDEX IF NOT EXISTS idx_consumption_entries_food_item_id ON consumption_entries(food_item_id);',
    'CREATE INDEX IF NOT EXISTS idx_consumption_entries_source_meal_id ON consumption_entries(source_meal_id) WHERE source_meal_id IS NOT NULL;',
    'CREATE INDEX IF NOT EXISTS idx_consumption_entries_meal_occurrence_id ON consumption_entries(meal_occurrence_id) WHERE meal_occurrence_id IS NOT NULL;',
    // Workout logging (story 141 / spike 138) — mirrors migration 017.
    `CREATE TABLE IF NOT EXISTS exercises (
        id TEXT PRIMARY KEY,
        canonical_name TEXT NOT NULL,
        display_name TEXT NOT NULL,
        category TEXT NOT NULL CHECK(category IN (
            'squat','hinge','push','pull','lunge','core','olympic','carry','bodyweight','other'
        )),
        default_unit TEXT NOT NULL DEFAULT 'kg' CHECK(default_unit IN ('kg','lb','bodyweight')),
        tracks_reps INTEGER NOT NULL DEFAULT 1,
        tracks_weight INTEGER NOT NULL DEFAULT 1,
        tracks_duration INTEGER NOT NULL DEFAULT 0,
        notes TEXT,
        use_count INTEGER NOT NULL DEFAULT 0,
        last_used_at TEXT,
        archived_at TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    ) STRICT;`,
    'CREATE INDEX IF NOT EXISTS idx_exercises_canonical_name ON exercises(canonical_name);',
    'CREATE INDEX IF NOT EXISTS idx_exercises_usage ON exercises(use_count DESC, last_used_at DESC);',
    `CREATE TABLE IF NOT EXISTS cardio_details (
        activity_id TEXT PRIMARY KEY,
        distance_m REAL,
        elevation_gain_m REAL,
        avg_speed_mps REAL,
        avg_hr INTEGER,
        max_hr INTEGER,
        gear_name TEXT,
        strava_sport_type TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now')),
        FOREIGN KEY (activity_id) REFERENCES activities(id) ON DELETE CASCADE
    ) STRICT;`,
    `CREATE TABLE IF NOT EXISTS workout_templates (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        notes TEXT,
        use_count INTEGER NOT NULL DEFAULT 0,
        last_used_at TEXT,
        archived_at TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    ) STRICT;`,
    `CREATE TABLE IF NOT EXISTS workout_sessions (
        activity_id TEXT PRIMARY KEY,
        source_template_id TEXT,
        notes TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now')),
        FOREIGN KEY (activity_id) REFERENCES activities(id) ON DELETE CASCADE,
        FOREIGN KEY (source_template_id) REFERENCES workout_templates(id) ON DELETE SET NULL
    ) STRICT;`,
    `CREATE TABLE IF NOT EXISTS strength_sets (
        id TEXT PRIMARY KEY,
        session_id TEXT NOT NULL,
        position INTEGER NOT NULL,
        exercise_id TEXT NOT NULL,
        set_index INTEGER NOT NULL,
        reps INTEGER,
        weight_kg REAL,
        rpe REAL,
        rest_s INTEGER,
        notes TEXT,
        FOREIGN KEY (session_id) REFERENCES workout_sessions(activity_id) ON DELETE CASCADE,
        FOREIGN KEY (exercise_id) REFERENCES exercises(id) ON DELETE RESTRICT
    ) STRICT;`,
    'CREATE INDEX IF NOT EXISTS idx_strength_sets_session ON strength_sets(session_id);',
    'CREATE INDEX IF NOT EXISTS idx_strength_sets_exercise_session ON strength_sets(exercise_id, session_id);',
    `CREATE TABLE IF NOT EXISTS workout_blocks (
        id TEXT PRIMARY KEY,
        session_id TEXT NOT NULL,
        position INTEGER NOT NULL,
        parent_label TEXT,
        kind TEXT NOT NULL CHECK(kind IN ('interval','rest','note')),
        modality TEXT,
        duration_s INTEGER,
        distance_m REAL,
        intensity TEXT,
        avg_hr INTEGER,
        notes TEXT,
        FOREIGN KEY (session_id) REFERENCES workout_sessions(activity_id) ON DELETE CASCADE
    ) STRICT;`,
    'CREATE INDEX IF NOT EXISTS idx_workout_blocks_session ON workout_blocks(session_id);',
    `CREATE TABLE IF NOT EXISTS template_strength_sets (
        id TEXT PRIMARY KEY,
        template_id TEXT NOT NULL,
        position INTEGER NOT NULL,
        exercise_id TEXT NOT NULL,
        target_set_count INTEGER NOT NULL,
        target_reps INTEGER,
        target_weight_kg REAL,
        target_rpe REAL,
        target_rest_s INTEGER,
        notes TEXT,
        FOREIGN KEY (template_id) REFERENCES workout_templates(id) ON DELETE CASCADE,
        FOREIGN KEY (exercise_id) REFERENCES exercises(id) ON DELETE RESTRICT
    ) STRICT;`,
    'CREATE INDEX IF NOT EXISTS idx_template_strength_sets_template ON template_strength_sets(template_id);',
    `CREATE TABLE IF NOT EXISTS template_blocks (
        id TEXT PRIMARY KEY,
        template_id TEXT NOT NULL,
        position INTEGER NOT NULL,
        parent_label TEXT,
        kind TEXT NOT NULL CHECK(kind IN ('interval','rest','note')),
        modality TEXT,
        target_duration_s INTEGER,
        target_distance_m REAL,
        target_intensity TEXT,
        notes TEXT,
        FOREIGN KEY (template_id) REFERENCES workout_templates(id) ON DELETE CASCADE
    ) STRICT;`,
    'CREATE INDEX IF NOT EXISTS idx_template_blocks_template ON template_blocks(template_id);',
];

export const GOALS_TABLES_SQL: string[] = [
    `CREATE TABLE IF NOT EXISTS goals (
        id TEXT PRIMARY KEY,
        parent_id TEXT,
        title TEXT NOT NULL,
        description TEXT,
        status TEXT CHECK(status IN ('ACTIVE', 'ON_HOLD', 'COMPLETED', 'ARCHIVED')) DEFAULT 'ACTIVE',
        created_at TEXT DEFAULT (datetime('now')),
        updated_at TEXT DEFAULT (datetime('now')),
        FOREIGN KEY (parent_id) REFERENCES goals(id) ON DELETE CASCADE
    );`,
    'CREATE INDEX IF NOT EXISTS idx_goals_parent_id ON goals(parent_id);',
];

export const SOCIAL_TABLES_SQL: string[] = [
    `CREATE TABLE IF NOT EXISTS people (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        relationship TEXT,
        notes TEXT,
        photo_url TEXT,
        created_at TEXT DEFAULT (datetime('now')),
        updated_at TEXT DEFAULT (datetime('now'))
    );`,
    `CREATE TABLE IF NOT EXISTS important_dates (
        id TEXT PRIMARY KEY,
        person_id TEXT NOT NULL,
        label TEXT NOT NULL,
        date TEXT NOT NULL,
        recurring INTEGER NOT NULL DEFAULT 1 CHECK(recurring IN (0, 1)),
        created_at TEXT DEFAULT (datetime('now')),
        FOREIGN KEY (person_id) REFERENCES people(id) ON DELETE CASCADE
    );`,
    'CREATE INDEX IF NOT EXISTS idx_important_dates_person_id ON important_dates(person_id);',
    `CREATE TABLE IF NOT EXISTS interactions (
        id TEXT PRIMARY KEY,
        person_id TEXT NOT NULL,
        type TEXT NOT NULL CHECK(type IN ('in_person', 'message', 'call', 'video')),
        date TEXT NOT NULL,
        notes TEXT,
        created_at TEXT DEFAULT (datetime('now')),
        FOREIGN KEY (person_id) REFERENCES people(id) ON DELETE CASCADE
    );`,
    'CREATE INDEX IF NOT EXISTS idx_interactions_person_id ON interactions(person_id);',
    'CREATE INDEX IF NOT EXISTS idx_interactions_date ON interactions(date);',
];

export const VIETNAMESE_TABLES_SQL: string[] = [
    `CREATE TABLE IF NOT EXISTS decks (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        description TEXT,
        created_at TEXT DEFAULT (datetime('now')),
        updated_at TEXT DEFAULT (datetime('now'))
    );`,
    `CREATE TABLE IF NOT EXISTS cards (
        id TEXT PRIMARY KEY,
        deck_id TEXT NOT NULL,
        front TEXT NOT NULL,
        back TEXT NOT NULL,
        notes TEXT,
        audio TEXT,
        created_at TEXT DEFAULT (datetime('now')),
        updated_at TEXT DEFAULT (datetime('now')),
        FOREIGN KEY (deck_id) REFERENCES decks(id) ON DELETE CASCADE
    );`,
    'CREATE INDEX IF NOT EXISTS idx_cards_deck_id ON cards(deck_id);',
    `CREATE TABLE IF NOT EXISTS reviews (
        id TEXT PRIMARY KEY,
        card_id TEXT NOT NULL,
        state TEXT NOT NULL DEFAULT 'new' CHECK(state IN ('new', 'learning', 'review', 'relearning')),
        stability REAL NOT NULL DEFAULT 0,
        difficulty REAL NOT NULL DEFAULT 0,
        scheduled_days INTEGER NOT NULL DEFAULT 0,
        elapsed_days INTEGER NOT NULL DEFAULT 0,
        rating INTEGER CHECK(rating IN (1, 2, 3, 4)),
        due TEXT NOT NULL DEFAULT (datetime('now')),
        last_review TEXT,
        created_at TEXT DEFAULT (datetime('now')),
        FOREIGN KEY (card_id) REFERENCES cards(id) ON DELETE CASCADE
    );`,
    'CREATE INDEX IF NOT EXISTS idx_reviews_card_id ON reviews(card_id);',
    'CREATE INDEX IF NOT EXISTS idx_reviews_due ON reviews(due);',
    'CREATE INDEX IF NOT EXISTS idx_reviews_state ON reviews(state);',
];

export const SETTINGS_TABLE_SQL: string[] = [
    `CREATE TABLE IF NOT EXISTS settings (
        key TEXT PRIMARY KEY,
        value TEXT NOT NULL,
        updated_at TEXT DEFAULT (datetime('now'))
    );`,
];

